def decay_power(S, T, t, d, priorB):
    # check what the 1+ efficiency is - its a scalar
    T1 = np.power(1+t+T.data, -d)
    S1 = S.data
    if S.format == 'lil':
        S1 = list(itertools.chain(*S1))
    T.data = S1 * T1
    newB =  T @ np.ones(T.shape[1])
    if type(priorB) == int:
        B = newB
    else:
        B = priorB + newB

    return(B)



